<?php require_once __DIR__ . '/../includes/session.php'; require_once __DIR__ . '/../includes/db.php'; if(!empty($_SESSION['admin_id'])) redirect('admin/dashboard.php'); $error=''; if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf($_POST['csrf']??null);$username=trim($_POST['username']??'');$s=db()->prepare('SELECT * FROM admin WHERE username=? LIMIT 1');$s->execute([$username]);$admin=$s->fetch();if($admin && password_verify($_POST['password']??'', $admin['password'])){session_regenerate_id(true);$_SESSION['admin_id']=$admin['id'];$_SESSION['admin_name']=$admin['name'];redirect('admin/dashboard.php');}$error='Invalid username or password.';} ?>
